window.PARASITIC_QUESTIONS.push(...[{"id":"Q051","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"MCQ","difficulty":"Hard","source":"PDF p. 196","question":{"en":"What is the usual cause of cutaneous larva migrans?","ar":"ما السبب المعتاد لهجرة اليرقات الجلدية؟"},"options":[{"letter":"A","en":"Adult human tapeworms in blood vessels","ar":"ديدان شريطية بشرية بالغة داخل الأوعية"},{"letter":"B","en":"A scabies mite laying eggs in hair","ar":"عثة جرب تضع البيض بالشعر"},{"letter":"C","en":"Skin penetration by animal hookworm larvae such as Ancylostoma braziliense","ar":"اختراق الجلد بيرقات ديدان خطافية حيوانية مثل أنكلستوما برازيليانس"},{"letter":"D","en":"Leishmania transmitted by lice","ar":"ليشمانيا ينقلها القمل"}],"correct":"C","explanation":{"en":"Dog and cat hookworm larvae penetrate exposed skin but cannot complete their life cycle in humans.","ar":"تخترق يرقات الديدان الخطافية للكلاب والقطط الجلد المكشوف لكنها لا تكمل دورة حياتها في الإنسان."},"reasoning":{"en":"The decisive clue is bare-skin exposure to contaminated soil or sand. This supports Skin penetration by animal hookworm larvae such as Ancylostoma braziliense and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي تعرض الجلد العاري لتربة أو رمل ملوث؛ ولذلك تدعم الإجابة «اختراق الجلد بيرقات ديدان خطافية حيوانية مثل أنكلستوما برازيليانس» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q052","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"MCQ","difficulty":"Hard","source":"PDF p. 196","question":{"en":"Which lesion morphology is typical of cutaneous larva migrans?","ar":"أي شكل للآفة نموذجي لهجرة اليرقات الجلدية؟"},"options":[{"letter":"A","en":"A fixed round painless ulcer","ar":"قرحة دائرية ثابتة غير مؤلمة"},{"letter":"B","en":"Nits fixed to hair","ar":"صئبان مثبتة بالشعر"},{"letter":"C","en":"Thick diffuse scabies crusts","ar":"قشور جرب سميكة منتشرة"},{"letter":"D","en":"An intensely pruritic raised erythematous serpiginous track","ar":"مسار مرتفع محمر متعرج شديد الحكة"}],"correct":"D","explanation":{"en":"The migrating larva creates a creeping, winding inflammatory track.","ar":"تصنع اليرقة المهاجرة مسارًا التهابيًا زاحفًا ومتعرجًا."},"reasoning":{"en":"The decisive clue is the creeping serpiginous track. This supports An intensely pruritic raised erythematous serpiginous track and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي المسار الزاحف المتعرج؛ ولذلك تدعم الإجابة «مسار مرتفع محمر متعرج شديد الحكة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q053","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"MCQ","difficulty":"Hard","source":"PDF p. 197","question":{"en":"How fast does a typical cutaneous larva migrans track advance?","ar":"ما سرعة تقدم مسار هجرة اليرقات الجلدية عادةً؟"},"options":[{"letter":"A","en":"About 1–2 cm per day","ar":"نحو 1–2 سم يوميًا"},{"letter":"B","en":"One meter per hour","ar":"متر واحد كل ساعة"},{"letter":"C","en":"It never moves","ar":"لا يتحرك"},{"letter":"D","en":"One millimeter per year","ar":"ملليمتر واحد سنويًا"}],"correct":"A","explanation":{"en":"Daily visible progression is a useful clue separating CLM from static dermatitis.","ar":"يمثل التقدم المرئي يوميًا علامة مفيدة لتمييزها عن التهاب الجلد الثابت."},"reasoning":{"en":"The decisive clue is measurable daily migration. This supports About 1–2 cm per day and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الهجرة اليومية القابلة للقياس؛ ولذلك تدعم الإجابة «نحو 1–2 سم يوميًا» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q054","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"MCQ","difficulty":"Hard","source":"PDF p. 197","question":{"en":"Which systemic finding is typical in uncomplicated cutaneous larva migrans?","ar":"أي علامة جهازية نموذجية في هجرة اليرقات الجلدية غير المعقدة؟"},"options":[{"letter":"A","en":"Severe pancytopenia is universal","ar":"نقص شامل شديد بخلايا الدم دائمًا"},{"letter":"B","en":"Systemic symptoms are usually absent; eosinophilia is uncommon","ar":"تغيب الأعراض الجهازية عادةً وتكون زيادة الحمضات غير شائعة"},{"letter":"C","en":"Hepatosplenomegaly is expected","ar":"يُتوقع تضخم الكبد والطحال"},{"letter":"D","en":"High fever occurs in every case","ar":"تحدث حمى مرتفعة في كل الحالات"}],"correct":"B","explanation":{"en":"CLM remains confined to the superficial skin in most patients.","ar":"تبقى هجرة اليرقات الجلدية محصورة في الجلد السطحي لدى معظم المرضى."},"reasoning":{"en":"The decisive clue is localized skin disease without systemic illness. This supports Systemic symptoms are usually absent; eosinophilia is uncommon and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي مرض جلدي موضعي دون اعتلال جهازي؛ ولذلك تدعم الإجابة «تغيب الأعراض الجهازية عادةً وتكون زيادة الحمضات غير شائعة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q055","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"MCQ","difficulty":"Hard","source":"PDF p. 197","question":{"en":"What is the natural course of untreated cutaneous larva migrans in most patients?","ar":"ما المسار الطبيعي لهجرة اليرقات الجلدية دون علاج لدى معظم المرضى؟"},"options":[{"letter":"A","en":"It always causes permanent visceral infection","ar":"يسبب دائمًا عدوى حشوية دائمة"},{"letter":"B","en":"It resolves within five minutes","ar":"يختفي خلال خمس دقائق"},{"letter":"C","en":"It is self-limited over roughly 2–8 weeks","ar":"مرض محدود ذاتيًا خلال نحو 2–8 أسابيع"},{"letter":"D","en":"It becomes human-to-human contagious","ar":"يصبح معديًا بين البشر"}],"correct":"C","explanation":{"en":"The larvae cannot mature in humans and eventually die, although treatment shortens severe itching.","ar":"لا تستطيع اليرقات النضج في الإنسان وتموت في النهاية، لكن العلاج يقصر مدة الحكة الشديدة."},"reasoning":{"en":"The decisive clue is the dead-end human host. This supports It is self-limited over roughly 2–8 weeks and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي كون الإنسان عائلًا غير مناسب لإكمال الدورة؛ ولذلك تدعم الإجابة «مرض محدود ذاتيًا خلال نحو 2–8 أسابيع» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q056","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Easy","source":"PDF p. 169","question":{"en":"A 24-year-old and two family members develop intense nocturnal itching. Examination shows tiny serpiginous lines in the finger webs. What is the most likely diagnosis?","ar":"شاب عمره 24 عامًا واثنان من أفراد أسرته أصيبوا بحكة ليلية شديدة، وتوجد خطوط متعرجة دقيقة بين الأصابع. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Head lice","ar":"قمل الرأس"},{"letter":"B","en":"Localized cutaneous leishmaniasis","ar":"الليشمانيا الجلدية الموضعية"},{"letter":"C","en":"Cutaneous larva migrans","ar":"هجرة اليرقات الجلدية"},{"letter":"D","en":"Classic scabies","ar":"الجرب التقليدي"}],"correct":"D","explanation":{"en":"Household clustering, nocturnal pruritus, and finger-web burrows are classic for scabies.","ar":"تجمع الحالات داخل الأسرة مع الحكة الليلية والأنفاق بين الأصابع صورة كلاسيكية للجرب."},"reasoning":{"en":"The decisive clue is household nocturnal itch plus burrows. This supports Classic scabies and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الحكة الليلية الأسرية مع الأنفاق؛ ولذلك تدعم الإجابة «الجرب التقليدي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q057","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Easy","source":"PDF p. 169","question":{"en":"A nurse previously treated for scabies develops generalized itching two days after caring for an infested patient. What explains the rapid onset?","ar":"ممرضة عولجت سابقًا من الجرب أصيبت بحكة عامة بعد يومين من رعاية مريض مصاب. ما تفسير البداية السريعة؟"},"options":[{"letter":"A","en":"Reinfestation in a previously sensitized host","ar":"إعادة الإصابة لدى شخص متحسس سابقًا"},{"letter":"B","en":"Primary infestation requiring six weeks","ar":"إصابة أولية تحتاج ستة أسابيع"},{"letter":"C","en":"Zoonotic scabies from a dog","ar":"جرب حيواني من كلب"},{"letter":"D","en":"Drug allergy to antibiotics","ar":"حساسية لمضاد حيوي"}],"correct":"A","explanation":{"en":"Previously primed immunity produces symptoms within days rather than weeks.","ar":"تؤدي المناعة المهيأة سابقًا إلى ظهور الأعراض خلال أيام بدلًا من أسابيع."},"reasoning":{"en":"The decisive clue is prior scabies with symptoms in 48 hours. This supports Reinfestation in a previously sensitized host and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي إصابة سابقة مع أعراض خلال 48 ساعة؛ ولذلك تدعم الإجابة «إعادة الإصابة لدى شخص متحسس سابقًا» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q058","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Easy","source":"PDF p. 171","question":{"en":"A 7-month-old has pruritic vesiculopustules on the palms, soles, scalp, and face. His parents also itch at night. What is the best diagnosis?","ar":"رضيع عمره 7 أشهر لديه حويصلات وبثرات حاكة على الراحتين والأخمصين وفروة الرأس والوجه، ووالداه يعانيان حكة ليلية. ما التشخيص الأفضل؟"},"options":[{"letter":"A","en":"Adult-pattern scabies is impossible","ar":"الجرب بنمط البالغين مستحيل"},{"letter":"B","en":"Infantile scabies","ar":"جرب الرضع"},{"letter":"C","en":"Pubic lice","ar":"قمل العانة"},{"letter":"D","en":"Leishmaniasis recidivans","ar":"الليشمانيا الناكسة"}],"correct":"B","explanation":{"en":"Infants commonly have head, palm, and sole involvement, especially with affected household contacts.","ar":"يشيع لدى الرضع إصابة الرأس والراحتين والأخمصين خاصة مع إصابة المخالطين بالمنزل."},"reasoning":{"en":"The decisive clue is age-specific distribution with family itch. This supports Infantile scabies and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التوزيع المرتبط بالعمر مع حكة الأسرة؛ ولذلك تدعم الإجابة «جرب الرضع» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q059","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Easy","source":"PDF p. 171","question":{"en":"An elderly immunosuppressed patient in a nursing home develops thick warty crusts on the hands, feet, elbows, and scalp with minimal itching. What is the diagnosis?","ar":"مريض مسن مثبط المناعة بدار رعاية ظهرت لديه قشور ثؤلولية سميكة على اليدين والقدمين والمرفقين وفروة الرأس مع حكة بسيطة. ما التشخيص؟"},"options":[{"letter":"A","en":"Scabies in the clean","ar":"الجرب لدى شديدي النظافة"},{"letter":"B","en":"Head lice","ar":"قمل الرأس"},{"letter":"C","en":"Crusted scabies","ar":"الجرب المتقشر"},{"letter":"D","en":"Tinea versicolor","ar":"النخالية المبرقشة"}],"correct":"C","explanation":{"en":"Crusted scabies produces massive hyperkeratosis and may cause little itch in immunocompromised hosts.","ar":"يسبب الجرب المتقشر فرط تقرن هائل وقد تكون الحكة قليلة لدى مثبطي المناعة."},"reasoning":{"en":"The decisive clue is hyperkeratotic crusts in an immunosuppressed institutionalized patient. This supports Crusted scabies and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي القشور مفرطة التقرن لدى مثبط مناعة بمؤسسة رعاية؛ ولذلك تدعم الإجابة «الجرب المتقشر» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q060","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Easy","source":"PDF p. 170","question":{"en":"A patient repeatedly uses a potent steroid for an itchy rash. The redness fades temporarily, but the eruption spreads and no typical burrows are obvious. What should be suspected?","ar":"يستخدم مريض ستيرويدًا قويًا مرارًا لطفح حاك؛ يخف الاحمرار مؤقتًا لكن الطفح ينتشر ولا تبدو الأنفاق النموذجية واضحة. ماذا يُشتبه؟"},"options":[{"letter":"A","en":"Successful eradication of scabies","ar":"القضاء الناجح على الجرب"},{"letter":"B","en":"Body lice in clothing seams","ar":"قمل الجسم في درزات الملابس"},{"letter":"C","en":"Mucosal leishmaniasis","ar":"الليشمانيا المخاطية"},{"letter":"D","en":"Scabies incognito","ar":"الجرب المتخفي"}],"correct":"D","explanation":{"en":"Corticosteroids can mask inflammation while mites remain active.","ar":"قد تخفي الكورتيكوستيرويدات الالتهاب بينما يظل العث نشطًا."},"reasoning":{"en":"The decisive clue is steroid-modified spreading infestation. This supports Scabies incognito and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي إصابة منتشرة معدلة بالستيرويد؛ ولذلك تدعم الإجابة «الجرب المتخفي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q061","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Medium","source":"PDF p. 170","question":{"en":"A dog owner develops a few itchy papules only where the dog rested on his arms. There are no burrows, and no family member is affected. What is most likely?","ar":"صاحب كلب ظهرت لديه حطاطات حاكة قليلة فقط في مواضع ملامسة الكلب لذراعيه، دون أنفاق أو إصابة أفراد الأسرة. ما الأرجح؟"},"options":[{"letter":"A","en":"Zoonotic scabies","ar":"الجرب الحيواني المنشأ"},{"letter":"B","en":"Classic human scabies","ar":"الجرب البشري التقليدي"},{"letter":"C","en":"Crusted scabies","ar":"الجرب المتقشر"},{"letter":"D","en":"Pediculosis corporis","ar":"قمل الجسم"}],"correct":"A","explanation":{"en":"Animal mites cause a short, contact-site eruption without sustained person-to-person transmission.","ar":"تسبب عث الحيوانات طفحًا قصيرًا في موضع التلامس دون انتقال مستمر بين البشر."},"reasoning":{"en":"The decisive clue is animal exposure, contact-site papules, absent burrows. This supports Zoonotic scabies and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التعرض لحيوان وحطاطات موضعية وغياب الأنفاق؛ ولذلك تدعم الإجابة «الجرب الحيواني المنشأ» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q062","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Medium","source":"PDF p. 171","question":{"en":"After correctly completed scabies treatment, a man has persistent intensely itchy reddish-brown nodules on the scrotum for six weeks but no new burrows. What is the best explanation?","ar":"بعد إكمال علاج الجرب بصورة صحيحة، استمرت لدى رجل عقيدات بنية محمرة شديدة الحكة على الصفن ستة أسابيع دون أنفاق جديدة. ما التفسير الأفضل؟"},"options":[{"letter":"A","en":"Definite live-mite persistence","ar":"استمرار مؤكد للعث الحي"},{"letter":"B","en":"Post-scabetic nodular hypersensitivity","ar":"فرط حساسية عقدي بعد الجرب"},{"letter":"C","en":"Pubic lice because every genital itch is lice","ar":"قمل العانة لأن كل حكة تناسلية قمل"},{"letter":"D","en":"Cutaneous larva migrans","ar":"هجرة اليرقات الجلدية"}],"correct":"B","explanation":{"en":"Nodular inflammation can persist after eradication and does not automatically prove treatment failure.","ar":"قد يستمر الالتهاب العقدي بعد القضاء على العث ولا يثبت تلقائيًا فشل العلاج."},"reasoning":{"en":"The decisive clue is persistent nodules without new burrows. This supports Post-scabetic nodular hypersensitivity and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي عقيدات مستمرة دون أنفاق جديدة؛ ولذلك تدعم الإجابة «فرط حساسية عقدي بعد الجرب» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q063","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Medium","source":"PDF p. 171","question":{"en":"A highly hygienic patient who showers several times daily has severe nocturnal itching but only a few faint papules. Which variant should be considered?","ar":"مريض شديد النظافة يستحم عدة مرات يوميًا لديه حكة ليلية شديدة لكن حطاطات قليلة خافتة. أي نمط يجب التفكير فيه؟"},"options":[{"letter":"A","en":"Crusted scabies","ar":"الجرب المتقشر"},{"letter":"B","en":"Diffuse cutaneous leishmaniasis","ar":"الليشمانيا الجلدية المنتشرة"},{"letter":"C","en":"Scabies in the clean","ar":"الجرب لدى شديدي النظافة"},{"letter":"D","en":"Body lice","ar":"قمل الجسم"}],"correct":"C","explanation":{"en":"Frequent bathing may make lesions sparse while pruritus remains prominent.","ar":"قد يجعل الاستحمام المتكرر الآفات قليلة بينما تظل الحكة واضحة."},"reasoning":{"en":"The decisive clue is intense itch despite scant lesions. This supports Scabies in the clean and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي حكة شديدة رغم قلة الآفات؛ ولذلك تدعم الإجابة «الجرب لدى شديدي النظافة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q064","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Medium","source":"PDF p. 175","question":{"en":"A child with untreated scabies develops honey-colored crusts and increasing tenderness over excoriated lesions. What complication is most likely?","ar":"طفل لديه جرب غير معالج ظهرت فوق خدوشه قشور بلون العسل مع ازدياد الألم. ما المضاعفة الأرجح؟"},"options":[{"letter":"A","en":"Mucosal leishmaniasis","ar":"ليشمانيا مخاطية"},{"letter":"B","en":"Post-scabetic nodules only","ar":"عقيدات ما بعد الجرب فقط"},{"letter":"C","en":"A normal treatment reaction","ar":"تفاعل علاجي طبيعي"},{"letter":"D","en":"Secondary bacterial infection","ar":"عدوى بكتيرية ثانوية"}],"correct":"D","explanation":{"en":"Excoriations permit staphylococcal or streptococcal superinfection.","ar":"تسمح الخدوش بعدوى ثانوية بالمكورات العنقودية أو العقدية."},"reasoning":{"en":"The decisive clue is tender impetiginized crusts. This supports Secondary bacterial infection and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي قشور مؤلمة متقيحة؛ ولذلك تدعم الإجابة «عدوى بكتيرية ثانوية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q065","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Medium","source":"PDF p. 172","question":{"en":"A pregnant woman has classic scabies with nocturnal itching and wrist burrows. Which agent is the preferred first-line option?","ar":"حامل لديها جرب تقليدي مع حكة ليلية وأنفاق بالرسغ. ما الدواء المفضل كخط أول؟"},"options":[{"letter":"A","en":"Permethrin 5% cream","ar":"كريم بيرمثرين 5%"},{"letter":"B","en":"Oral ivermectin","ar":"إيفرمكتين فموي"},{"letter":"C","en":"Lindane","ar":"ليندان"},{"letter":"D","en":"Systemic corticosteroid alone","ar":"كورتيكوستيرويد جهازي فقط"}],"correct":"A","explanation":{"en":"Permethrin has low systemic absorption and is preferred in pregnancy.","ar":"يمتلك البيرمثرين امتصاصًا جهازيًا منخفضًا ويُفضل في الحمل."},"reasoning":{"en":"The decisive clue is pregnancy with classic scabies. This supports Permethrin 5% cream and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الحمل مع جرب تقليدي؛ ولذلك تدعم الإجابة «كريم بيرمثرين 5%» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q066","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Medium","source":"PDF p. 174","question":{"en":"A 6-week-old infant is diagnosed with scabies. Which treatment is most appropriate?","ar":"رضيع عمره ستة أسابيع شُخص بالجرب. ما العلاج الأنسب؟"},"options":[{"letter":"A","en":"Permethrin 5% under standard labeling","ar":"بيرمثرين 5% وفق الاستخدام المعتاد"},{"letter":"B","en":"Topical sulfur","ar":"الكبريت الموضعي"},{"letter":"C","en":"Oral ivermectin","ar":"إيفرمكتين فموي"},{"letter":"D","en":"Lindane","ar":"ليندان"}],"correct":"B","explanation":{"en":"Sulfur is preferred below two months because permethrin is not approved for this age and oral ivermectin is inappropriate.","ar":"يُفضل الكبريت تحت عمر شهرين لأن البيرمثرين غير معتمد لهذا العمر والإيفرمكتين الفموي غير مناسب."},"reasoning":{"en":"The decisive clue is age below two months. This supports Topical sulfur and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي عمر أقل من شهرين؛ ولذلك تدعم الإجابة «الكبريت الموضعي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q067","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Medium","source":"PDF p. 174","question":{"en":"A 3-year-old child weighs 12 kg and has widespread scabies after incomplete topical treatment. Which systemic option should be avoided?","ar":"طفل عمره ثلاث سنوات وزنه 12 كجم لديه جرب واسع بعد علاج موضعي غير مكتمل. أي خيار جهازي يجب تجنبه؟"},"options":[{"letter":"A","en":"Correctly applied permethrin","ar":"البيرمثرين المطبق بصورة صحيحة"},{"letter":"B","en":"Topical sulfur","ar":"الكبريت الموضعي"},{"letter":"C","en":"Oral ivermectin","ar":"الإيفرمكتين الفموي"},{"letter":"D","en":"Contact treatment","ar":"علاج المخالطين"}],"correct":"C","explanation":{"en":"Oral ivermectin is generally not recommended below 15 kg.","ar":"لا يُوصى عادةً بالإيفرمكتين الفموي تحت وزن 15 كجم."},"reasoning":{"en":"The decisive clue is body weight below the safety threshold. This supports Oral ivermectin and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الوزن دون حد الأمان؛ ولذلك تدعم الإجابة «الإيفرمكتين الفموي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q068","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Medium","source":"PDF p. 171","question":{"en":"Several residents and staff develop itching after exposure to one patient with thick diffuse crusts. Why did this index case trigger a large outbreak?","ar":"أصيب عدة نزلاء وموظفين بالحكة بعد التعرض لمريض واحد لديه قشور سميكة منتشرة. لماذا تسبب هذا المريض في تفشٍ كبير؟"},"options":[{"letter":"A","en":"Classic scabies is airborne over long distances","ar":"الجرب التقليدي ينتقل هوائيًا لمسافات بعيدة"},{"letter":"B","en":"The patient had leishmaniasis","ar":"كان المريض مصابًا بالليشمانيا"},{"letter":"C","en":"All itching in institutions is psychological","ar":"كل الحكة في المؤسسات نفسية"},{"letter":"D","en":"Crusted scabies carries an extremely high mite burden and is highly contagious","ar":"الجرب المتقشر يحمل عددًا هائلًا من العث وشديد العدوى"}],"correct":"D","explanation":{"en":"Millions of mites contaminate skin scales, clothing, bedding, and the environment.","ar":"تلوث ملايين العث القشور والملابس والفراش والبيئة."},"reasoning":{"en":"The decisive clue is institutional outbreak from a heavily crusted patient. This supports Crusted scabies carries an extremely high mite burden and is highly contagious and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي تفشٍ مؤسسي من مريض شديد التقشر؛ ولذلك تدعم الإجابة «الجرب المتقشر يحمل عددًا هائلًا من العث وشديد العدوى» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q069","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Medium","source":"PDF p. 172","question":{"en":"A patient applied permethrin only to visible papules for two hours and remained symptomatic. What is the most likely reason for failure?","ar":"وضع مريض البيرمثرين فقط على الحطاطات الظاهرة لمدة ساعتين وظلت الأعراض. ما السبب الأرجح للفشل؟"},"options":[{"letter":"A","en":"Incorrect coverage and insufficient contact time","ar":"تغطية غير كاملة ومدة تلامس غير كافية"},{"letter":"B","en":"Universal permethrin resistance","ar":"مقاومة عالمية للبيرمثرين"},{"letter":"C","en":"The diagnosis must be leishmaniasis","ar":"لابد أن التشخيص ليشمانيا"},{"letter":"D","en":"Post-scabetic itch can never occur","ar":"لا تحدث حكة بعد علاج الجرب"}],"correct":"A","explanation":{"en":"Permethrin must cover the entire recommended skin surface and remain for 8–14 hours.","ar":"يجب أن يغطي البيرمثرين كامل السطح المطلوب ويبقى 8–14 ساعة."},"reasoning":{"en":"The decisive clue is spot treatment for only two hours. This supports Incorrect coverage and insufficient contact time and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي العلاج النقطي لساعتين فقط؛ ولذلك تدعم الإجابة «تغطية غير كاملة ومدة تلامس غير كافية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q070","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"Case","difficulty":"Medium","source":"PDF p. 175","question":{"en":"Two weeks after properly treating all contacts, a patient still has mild itching but no new lesions or burrows. What is the best interpretation?","ar":"بعد أسبوعين من علاج جميع المخالطين بصورة صحيحة، بقيت حكة بسيطة دون آفات أو أنفاق جديدة. ما التفسير الأفضل؟"},"options":[{"letter":"A","en":"Immediate retreatment with seven ivermectin doses is mandatory","ar":"يجب فورًا إعطاء سبع جرعات إيفرمكتين"},{"letter":"B","en":"Post-scabetic pruritus may persist after successful eradication","ar":"قد تستمر حكة ما بعد الجرب رغم القضاء الناجح على العث"},{"letter":"C","en":"The patient has body lice","ar":"لدى المريض قمل جسم"},{"letter":"D","en":"Treatment certainly failed","ar":"فشل العلاج مؤكد"}],"correct":"B","explanation":{"en":"Hypersensitivity can take time to resolve; new burrows or active lesions would be more concerning for failure.","ar":"قد يستغرق فرط الحساسية وقتًا ليزول، وتكون الأنفاق أو الآفات الجديدة أكثر دلالة على الفشل."},"reasoning":{"en":"The decisive clue is itch without new objective lesions. This supports Post-scabetic pruritus may persist after successful eradication and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي حكة دون آفات موضوعية جديدة؛ ولذلك تدعم الإجابة «قد تستمر حكة ما بعد الجرب رغم القضاء الناجح على العث» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q071","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 177","question":{"en":"A schoolchild has scalp itching concentrated behind the ears and at the nape. Oval structures are firmly attached near the scalp. What is the diagnosis?","ar":"طفل مدرسي لديه حكة خلف الأذنين وعند مؤخرة الرقبة، وتوجد أجسام بيضاوية مثبتة بقوة قرب فروة الرأس. ما التشخيص؟"},"options":[{"letter":"A","en":"Dandruff","ar":"قشرة الشعر"},{"letter":"B","en":"Scabies","ar":"الجرب"},{"letter":"C","en":"Pediculosis capitis","ar":"قمل الرأس"},{"letter":"D","en":"Cutaneous leishmaniasis","ar":"الليشمانيا الجلدية"}],"correct":"C","explanation":{"en":"The distribution and fixed nits are classic for head lice.","ar":"التوزيع والصئبان المثبتة بقوة كلاسيكيان لقمل الرأس."},"reasoning":{"en":"The decisive clue is postauricular itch with firmly attached nits. This supports Pediculosis capitis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي حكة خلف الأذن مع صئبان مثبتة؛ ولذلك تدعم الإجابة «قمل الرأس» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q072","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 177","question":{"en":"A parent can easily brush white flakes from a child’s hair, and no live lice are seen. What is the most likely explanation?","ar":"يمكن للأم إزالة قشور بيضاء بسهولة من شعر طفلها ولا يوجد قمل حي. ما التفسير الأرجح؟"},"options":[{"letter":"A","en":"Definite head lice","ar":"قمل رأس مؤكد"},{"letter":"B","en":"Pubic lice","ar":"قمل العانة"},{"letter":"C","en":"Body lice","ar":"قمل الجسم"},{"letter":"D","en":"Dandruff rather than viable nits","ar":"قشرة الشعر وليست صئبانًا حية"}],"correct":"D","explanation":{"en":"Dandruff is loose, whereas nits are cemented to the hair shaft.","ar":"قشرة الشعر سائبة بينما تلتصق الصئبان بساق الشعرة."},"reasoning":{"en":"The decisive clue is easy removal from hair. This supports Dandruff rather than viable nits and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي سهولة الإزالة من الشعر؛ ولذلك تدعم الإجابة «قشرة الشعر وليست صئبانًا حية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q073","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 177","question":{"en":"A person living in crowded poor-hygiene conditions has generalized itch. Lice and eggs are found mainly in clothing seams. Which infestation is present?","ar":"شخص يعيش في ازدحام وسوء نظافة لديه حكة عامة، ويوجد القمل والبيض أساسًا في درزات الملابس. ما نوع الإصابة؟"},"options":[{"letter":"A","en":"Pediculosis corporis","ar":"قمل الجسم"},{"letter":"B","en":"Pediculosis capitis","ar":"قمل الرأس"},{"letter":"C","en":"Scabies in the clean","ar":"الجرب لدى شديدي النظافة"},{"letter":"D","en":"Pubic lice only","ar":"قمل العانة فقط"}],"correct":"A","explanation":{"en":"Body lice reside and reproduce in clothing seams rather than continuously on skin.","ar":"يعيش قمل الجسم ويتكاثر في درزات الملابس بدلًا من البقاء على الجلد باستمرار."},"reasoning":{"en":"The decisive clue is lice in fabric seams. This supports Pediculosis corporis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي القمل داخل درزات القماش؛ ولذلك تدعم الإجابة «قمل الجسم» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q074","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 177","question":{"en":"An adult has genital itching, visible lice on coarse pubic hair, and bluish-gray macules. What is the diagnosis?","ar":"بالغ لديه حكة تناسلية وقمل ظاهر على شعر العانة الخشن وبقع زرقاء رمادية. ما التشخيص؟"},"options":[{"letter":"A","en":"Genital scabies only","ar":"جرب تناسلي فقط"},{"letter":"B","en":"Pediculosis pubis","ar":"قمل العانة"},{"letter":"C","en":"Mucosal leishmaniasis","ar":"ليشمانيا مخاطية"},{"letter":"D","en":"Cutaneous larva migrans","ar":"هجرة اليرقات الجلدية"}],"correct":"B","explanation":{"en":"Maculae ceruleae and lice on coarse hair strongly indicate pubic lice.","ar":"تدل البقع الزرقاء الرمادية والقمل على الشعر الخشن بقوة على قمل العانة."},"reasoning":{"en":"The decisive clue is maculae ceruleae with visible crab lice. This supports Pediculosis pubis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي البقع الزرقاء مع قمل العانة المرئي؛ ولذلك تدعم الإجابة «قمل العانة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q075","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 178","question":{"en":"A child has lice attached to the eyelashes with blepharitis. What condition is this?","ar":"طفل لديه قمل ملتصق بالرموش مع التهاب جفن. ما الحالة؟"},"options":[{"letter":"A","en":"Head lice limited to the scalp","ar":"قمل رأس محدود بالفروة"},{"letter":"B","en":"Scabies keratitis","ar":"التهاب قرنية بالجرب"},{"letter":"C","en":"Phthiriasis palpebrarum","ar":"قمل الرموش"},{"letter":"D","en":"Leishmaniasis recidivans","ar":"الليشمانيا الناكسة"}],"correct":"C","explanation":{"en":"Pubic lice can infest eyelashes, particularly in children, causing blepharitis or conjunctivitis.","ar":"قد يصيب قمل العانة الرموش خاصة عند الأطفال ويسبب التهاب الجفن أو الملتحمة."},"reasoning":{"en":"The decisive clue is lice and nits on eyelashes. This supports Phthiriasis palpebrarum and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي قمل وصئبان على الرموش؛ ولذلك تدعم الإجابة «قمل الرموش» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q076","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 178","question":{"en":"A child with heavy head lice develops crusted excoriations, fever, and tender occipital nodes. What complication should be suspected?","ar":"طفل لديه قمل رأس كثيف ظهرت لديه خدوش متقشرة وحمى وعقد قذالية مؤلمة. ما المضاعفة المشتبه بها؟"},"options":[{"letter":"A","en":"Normal lice life cycle","ar":"دورة حياة طبيعية للقمل"},{"letter":"B","en":"Mucosal leishmaniasis","ar":"ليشمانيا مخاطية"},{"letter":"C","en":"Post-treatment irritation only","ar":"تهيج بعد العلاج فقط"},{"letter":"D","en":"Secondary bacterial infection","ar":"عدوى بكتيرية ثانوية"}],"correct":"D","explanation":{"en":"Scratching can produce impetiginization and regional lymphadenopathy.","ar":"قد يؤدي الحك إلى عدوى قوبائية وتضخم العقد اللمفاوية الإقليمية."},"reasoning":{"en":"The decisive clue is tender crusts, fever, and nodes. This supports Secondary bacterial infection and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي قشور مؤلمة وحمى وعقد؛ ولذلك تدعم الإجابة «عدوى بكتيرية ثانوية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q077","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 178","question":{"en":"A severely infested child is pale and fatigued with low hemoglobin. Which parasitic complication is plausible?","ar":"طفل شديد الإصابة بالقمل شاحب ومتعب ولديه هيموجلوبين منخفض. ما المضاعفة الطفيلية المحتملة؟"},"options":[{"letter":"A","en":"Anemia from chronic blood loss","ar":"أنيميا بسبب فقد دم مزمن"},{"letter":"B","en":"Hemolysis from scabies mites","ar":"انحلال دم بسبب عث الجرب"},{"letter":"C","en":"Pancytopenia from one nit","ar":"نقص شامل من صئبان واحدة"},{"letter":"D","en":"Acute liver failure","ar":"فشل كبدي حاد"}],"correct":"A","explanation":{"en":"Heavy prolonged lice feeding can rarely cause clinically important blood loss.","ar":"قد يسبب تغذي القمل الكثيف والمطول فقد دم مهمًا سريريًا بصورة نادرة."},"reasoning":{"en":"The decisive clue is heavy chronic infestation with anemia. This supports Anemia from chronic blood loss and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي إصابة مزمنة كثيفة مع أنيميا؛ ولذلك تدعم الإجابة «أنيميا بسبب فقد دم مزمن» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q078","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 178","question":{"en":"A refugee with body lice develops high fever and rash during an outbreak. Which vector-borne disease is most concerning?","ar":"لاجئ لديه قمل جسم أصيب بحمى مرتفعة وطفح أثناء تفشٍ. أي مرض منقول بالنواقل هو الأكثر إثارة للقلق؟"},"options":[{"letter":"A","en":"Varicella","ar":"الجديري المائي"},{"letter":"B","en":"Epidemic typhus","ar":"التيفوس الوبائي"},{"letter":"C","en":"Tinea corporis","ar":"سعفة الجسم"},{"letter":"D","en":"Scabies incognito","ar":"الجرب المتخفي"}],"correct":"B","explanation":{"en":"Crowding plus body lice creates risk of Rickettsia prowazekii transmission.","ar":"يؤدي الازدحام مع قمل الجسم إلى خطر انتقال ريكتسيا بروفازيكي."},"reasoning":{"en":"The decisive clue is body lice in an outbreak setting. This supports Epidemic typhus and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي قمل الجسم في سياق تفشٍ؛ ولذلك تدعم الإجابة «التيفوس الوبائي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q079","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 179","question":{"en":"A family used permethrin exactly as directed twice, but live crawling lice remain. What is the most likely next concern?","ar":"استخدمت أسرة البيرمثرين بصورة صحيحة مرتين لكن بقي قمل حي متحرك. ما القلق التالي الأرجح؟"},"options":[{"letter":"A","en":"The presence of empty nits proves failure","ar":"وجود صئبان فارغة يثبت الفشل"},{"letter":"B","en":"The condition must be scabies","ar":"لابد أن الحالة جرب"},{"letter":"C","en":"Local pyrethroid resistance","ar":"مقاومة موضعية للبيرثرويد"},{"letter":"D","en":"Treatment should be stopped permanently","ar":"يجب إيقاف العلاج نهائيًا"}],"correct":"C","explanation":{"en":"True live lice after correct repeated therapy suggests resistance rather than poor adherence.","ar":"وجود قمل حي بعد علاج متكرر صحيح يوحي بالمقاومة لا بضعف الالتزام."},"reasoning":{"en":"The decisive clue is live lice after correctly timed applications. This supports Local pyrethroid resistance and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي قمل حي بعد تطبيقات صحيحة التوقيت؛ ولذلك تدعم الإجابة «مقاومة موضعية للبيرثرويد» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q080","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 180","question":{"en":"A child with ragweed allergy needs treatment for head lice. Which product deserves caution?","ar":"طفل لديه حساسية من عشبة الرجيد يحتاج علاج قمل الرأس. أي منتج يستلزم الحذر؟"},"options":[{"letter":"A","en":"Wet combing","ar":"التمشيط الرطب"},{"letter":"B","en":"Topical ivermectin","ar":"الإيفرمكتين الموضعي"},{"letter":"C","en":"Spinosad","ar":"سبينوساد"},{"letter":"D","en":"Pyrethrins plus piperonyl butoxide","ar":"البيريثرينات مع بيبيرونيل بيوتوكسيد"}],"correct":"D","explanation":{"en":"Natural pyrethrins may trigger respiratory symptoms in patients allergic to ragweed.","ar":"قد تثير البيريثرينات الطبيعية أعراضًا تنفسية لدى مرضى حساسية الرجيد."},"reasoning":{"en":"The decisive clue is ragweed allergy. This supports Pyrethrins plus piperonyl butoxide and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي حساسية الرجيد؛ ولذلك تدعم الإجابة «البيريثرينات مع بيبيرونيل بيوتوكسيد» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q081","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 180","question":{"en":"An 8-month-old has confirmed head lice in an area with low resistance. Which first-line drug is age appropriate?","ar":"رضيع عمره ثمانية أشهر لديه قمل رأس مؤكد في منطقة منخفضة المقاومة. أي دواء من الخط الأول مناسب للعمر؟"},"options":[{"letter":"A","en":"Permethrin 1%","ar":"بيرمثرين 1%"},{"letter":"B","en":"Malathion","ar":"ملاثيون"},{"letter":"C","en":"Oral ivermectin","ar":"إيفرمكتين فموي"},{"letter":"D","en":"Lindane","ar":"ليندان"}],"correct":"A","explanation":{"en":"Permethrin 1% is permitted from two months, whereas several alternatives have older age limits.","ar":"يُسمح ببيرمثرين 1% من عمر شهرين بينما لبدائل أخرى حدود عمرية أكبر."},"reasoning":{"en":"The decisive clue is eight-month age with low resistance. This supports Permethrin 1% and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي عمر ثمانية أشهر مع مقاومة منخفضة؛ ولذلك تدعم الإجابة «بيرمثرين 1%» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q082","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 182","question":{"en":"A pregnant patient has head lice and asks for oral ivermectin because it is convenient. What is the safest response?","ar":"حامل لديها قمل رأس وتطلب الإيفرمكتين الفموي لسهولة استخدامه. ما الرد الأكثر أمانًا؟"},"options":[{"letter":"A","en":"Use high-dose oral ivermectin immediately","ar":"استخدام جرعة عالية فورًا"},{"letter":"B","en":"Avoid oral ivermectin and use an appropriate topical or mechanical option","ar":"تجنب الإيفرمكتين الفموي واستخدام خيار موضعي أو ميكانيكي مناسب"},{"letter":"C","en":"Use lindane as the safest option","ar":"استخدام ليندان كخيار آمن"},{"letter":"D","en":"No treatment is ever allowed in pregnancy","ar":"لا يجوز أي علاج في الحمل"}],"correct":"B","explanation":{"en":"Oral ivermectin safety is not established in pregnancy; safer local options are preferred.","ar":"لم يثبت أمان الإيفرمكتين الفموي في الحمل وتُفضل الخيارات الموضعية الأكثر أمانًا."},"reasoning":{"en":"The decisive clue is pregnancy and systemic ivermectin. This supports Avoid oral ivermectin and use an appropriate topical or mechanical option and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الحمل والإيفرمكتين الجهازي؛ ولذلك تدعم الإجابة «تجنب الإيفرمكتين الفموي واستخدام خيار موضعي أو ميكانيكي مناسب» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q083","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"Case","difficulty":"Medium","source":"PDF p. 189","question":{"en":"A child has completed effective head-lice treatment and no live lice are found, but the school refuses return because a few empty nits remain. Which statement is most accurate?","ar":"أكمل طفل علاج قمل الرأس بنجاح ولا يوجد قمل حي، لكن المدرسة ترفض عودته بسبب بقاء بعض الصئبان الفارغة. أي عبارة أدق؟"},"options":[{"letter":"A","en":"Empty nits always transmit active infestation","ar":"الصئبان الفارغة تنقل الإصابة دائمًا"},{"letter":"B","en":"The child requires hospitalization","ar":"يحتاج الطفل دخول المستشفى"},{"letter":"C","en":"A “no-nit” exclusion policy is generally unnecessary","ar":"سياسة منع العودة بسبب الصئبان وحدها غير ضرورية عادةً"},{"letter":"D","en":"All hair must be shaved","ar":"يجب حلق الشعر كله"}],"correct":"C","explanation":{"en":"Children can usually return after appropriate treatment; empty nits alone do not prove contagious infestation.","ar":"يمكن للأطفال العودة عادةً بعد العلاج المناسب ولا تثبت الصئبان الفارغة وحدها عدوى نشطة."},"reasoning":{"en":"The decisive clue is no live lice after treatment. This supports A “no-nit” exclusion policy is generally unnecessary and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي عدم وجود قمل حي بعد العلاج؛ ولذلك تدعم الإجابة «سياسة منع العودة بسبب الصئبان وحدها غير ضرورية عادةً» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q084","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Case","difficulty":"Medium","source":"PDF p. 191","question":{"en":"A traveler returns from an endemic desert region with a chronic painless ulcer on the forearm. The edge is raised and indurated. What is most likely?","ar":"عاد مسافر من منطقة صحراوية متوطنة بقرحة مزمنة غير مؤلمة على الساعد ذات حافة مرتفعة متصلبة. ما الأرجح؟"},"options":[{"letter":"A","en":"Scabies","ar":"الجرب"},{"letter":"B","en":"Head lice","ar":"قمل الرأس"},{"letter":"C","en":"Cutaneous larva migrans","ar":"هجرة اليرقات الجلدية"},{"letter":"D","en":"Localized cutaneous leishmaniasis","ar":"الليشمانيا الجلدية الموضعية"}],"correct":"D","explanation":{"en":"A chronic painless ulcer on exposed skin after sandfly exposure is typical.","ar":"القرحة المزمنة غير المؤلمة على جلد مكشوف بعد التعرض لذبابة الرمل نموذجية."},"reasoning":{"en":"The decisive clue is endemic travel plus indurated painless ulcer. This supports Localized cutaneous leishmaniasis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي السفر لمنطقة متوطنة مع قرحة متصلبة غير مؤلمة؛ ولذلك تدعم الإجابة «الليشمانيا الجلدية الموضعية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q085","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Case","difficulty":"Medium","source":"PDF p. 192","question":{"en":"Years after a cutaneous leishmaniasis lesion healed, small papules appear at the edge of the old scar. What is the likely diagnosis?","ar":"بعد سنوات من التئام آفة ليشمانيا جلدية، ظهرت حطاطات صغيرة عند حافة الندبة القديمة. ما التشخيص المحتمل؟"},"options":[{"letter":"A","en":"Leishmaniasis recidivans","ar":"الليشمانيا الناكسة"},{"letter":"B","en":"New scabies infestation","ar":"إصابة جرب جديدة"},{"letter":"C","en":"Pediculosis corporis","ar":"قمل الجسم"},{"letter":"D","en":"CLM","ar":"هجرة اليرقات الجلدية"}],"correct":"A","explanation":{"en":"Recidivans produces chronic reactivation around a healed scar.","ar":"تسبب الليشمانيا الناكسة إعادة نشاط مزمنة حول ندبة ملتئمة."},"reasoning":{"en":"The decisive clue is papules at an old scar years later. This supports Leishmaniasis recidivans and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي حطاطات حول ندبة قديمة بعد سنوات؛ ولذلك تدعم الإجابة «الليشمانيا الناكسة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q086","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Case","difficulty":"Hard","source":"PDF p. 194","question":{"en":"An immunologically anergic patient has numerous symmetric nonulcerating nodules over the face and limbs with very high parasite burden. What form is this?","ar":"مريض ضعيف الاستجابة المناعية لديه عقيدات متناظرة عديدة غير متقرحة على الوجه والأطراف مع حمل طفيلي مرتفع. ما النوع؟"},"options":[{"letter":"A","en":"Localized uncomplicated leishmaniasis","ar":"ليشمانيا موضعية غير معقدة"},{"letter":"B","en":"Diffuse cutaneous leishmaniasis","ar":"الليشمانيا الجلدية المنتشرة"},{"letter":"C","en":"Scabies in the clean","ar":"الجرب لدى شديدي النظافة"},{"letter":"D","en":"Body lice dermatitis","ar":"التهاب جلد بقمل الجسم"}],"correct":"B","explanation":{"en":"Diffuse disease reflects failure of cellular immunity to contain parasites.","ar":"يعكس المرض المنتشر فشل المناعة الخلوية في احتواء الطفيليات."},"reasoning":{"en":"The decisive clue is widespread nonulcerating lesions with anergy. This supports Diffuse cutaneous leishmaniasis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي آفات واسعة غير متقرحة مع ضعف الاستجابة؛ ولذلك تدعم الإجابة «الليشمانيا الجلدية المنتشرة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q087","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Case","difficulty":"Hard","source":"PDF p. 194","question":{"en":"A patient from South America develops progressive nasal obstruction, epistaxis, and destructive mucosal lesions months after a skin ulcer. What is most concerning?","ar":"مريض من أمريكا الجنوبية أصيب بانسداد أنفي متزايد ورعاف وآفات مخاطية مدمرة بعد أشهر من قرحة جلدية. ما الأكثر إثارة للقلق؟"},"options":[{"letter":"A","en":"Head lice","ar":"قمل الرأس"},{"letter":"B","en":"Classic scabies","ar":"الجرب التقليدي"},{"letter":"C","en":"Mucosal leishmaniasis","ar":"الليشمانيا المخاطية"},{"letter":"D","en":"Localized CLM","ar":"هجرة يرقات موضعية"}],"correct":"C","explanation":{"en":"New World species can disseminate to mucosa and cause destructive upper-airway disease.","ar":"قد تنتشر أنواع العالم الجديد إلى الأغشية المخاطية وتسبب مرضًا مدمرًا بالمجرى الهوائي العلوي."},"reasoning":{"en":"The decisive clue is destructive nasal disease after a cutaneous lesion. This supports Mucosal leishmaniasis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي مرض أنفي مدمر بعد آفة جلدية؛ ولذلك تدعم الإجابة «الليشمانيا المخاطية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q088","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Case","difficulty":"Hard","source":"PDF p. 192","question":{"en":"A patient has six cutaneous lesions, each 1.5–2 cm, after travel to a Viannia-endemic region. Which classification is most appropriate?","ar":"مريض لديه ست آفات جلدية حجم كل منها 1.5–2 سم بعد سفر لمنطقة متوطنة بفيانيا. ما التصنيف الأنسب؟"},"options":[{"letter":"A","en":"Automatically uncomplicated disease","ar":"مرض غير معقد تلقائيًا"},{"letter":"B","en":"Pediculosis","ar":"قمل"},{"letter":"C","en":"Scabies nodules","ar":"عقيدات جرب"},{"letter":"D","en":"Complicated cutaneous leishmaniasis requiring systemic assessment","ar":"ليشمانيا جلدية معقدة تحتاج تقييمًا لعلاج جهازي"}],"correct":"D","explanation":{"en":"Multiple lesions, size over 1 cm, and mucosal-risk species favor systemic treatment.","ar":"ترجح تعدد الآفات وحجمها فوق 1 سم والنوع ذي الخطر المخاطي العلاج الجهازي."},"reasoning":{"en":"The decisive clue is multiple large lesions with Viannia exposure. This supports Complicated cutaneous leishmaniasis requiring systemic assessment and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي آفات كبيرة متعددة مع التعرض لفيانيا؛ ولذلك تدعم الإجابة «ليشمانيا جلدية معقدة تحتاج تقييمًا لعلاج جهازي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q089","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Case","difficulty":"Hard","source":"PDF p. 192","question":{"en":"A small cutaneous leishmaniasis lesion is located on the eyelid. Why is this not a routine low-risk lesion?","ar":"توجد آفة ليشمانيا جلدية صغيرة على الجفن. لماذا لا تُعد آفة منخفضة الخطورة عادية؟"},"options":[{"letter":"A","en":"The eyelid is a functionally critical site where local destructive therapy may cause harm","ar":"الجفن موضع وظيفي حرج وقد يسبب العلاج الموضعي المدمر ضررًا"},{"letter":"B","en":"All eyelid lesions are body lice","ar":"كل آفات الجفن قمل جسم"},{"letter":"C","en":"The lesion cannot be parasitic","ar":"لا يمكن أن تكون الآفة طفيلية"},{"letter":"D","en":"Size is the only factor that matters","ar":"الحجم هو العامل الوحيد"}],"correct":"A","explanation":{"en":"High-risk anatomy can outweigh small lesion size when selecting treatment.","ar":"قد تتغلب خطورة الموضع على صغر حجم الآفة عند اختيار العلاج."},"reasoning":{"en":"The decisive clue is critical periocular location. This supports The eyelid is a functionally critical site where local destructive therapy may cause harm and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الموضع الحرج حول العين؛ ولذلك تدعم الإجابة «الجفن موضع وظيفي حرج وقد يسبب العلاج الموضعي المدمر ضررًا» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q090","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Case","difficulty":"Hard","source":"PDF p. 192","question":{"en":"An organ-transplant recipient has two small cutaneous leishmaniasis lesions. Why is systemic therapy more likely than in an immunocompetent patient?","ar":"مريض زرع عضو لديه آفتان صغيرتان من الليشمانيا الجلدية. لماذا يزداد احتمال العلاج الجهازي مقارنة بسليم المناعة؟"},"options":[{"letter":"A","en":"Transplant recipients cannot acquire parasites","ar":"مرضى الزرع لا يصابون بالطفيليات"},{"letter":"B","en":"Immunosuppression increases persistence, dissemination, and treatment failure risk","ar":"تثبيط المناعة يزيد خطر الاستمرار والانتشار وفشل العلاج"},{"letter":"C","en":"Local treatment is always curative","ar":"العلاج الموضعي يشفي دائمًا"},{"letter":"D","en":"All lesions heal within one day","ar":"كل الآفات تلتئم خلال يوم"}],"correct":"B","explanation":{"en":"Host immune status is a major criterion for classifying disease as complicated.","ar":"تُعد حالة مناعة العائل معيارًا رئيسيًا لتصنيف المرض كمعقد."},"reasoning":{"en":"The decisive clue is immunosuppressed host. This supports Immunosuppression increases persistence, dissemination, and treatment failure risk and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي العائل المثبط المناعة؛ ولذلك تدعم الإجابة «تثبيط المناعة يزيد خطر الاستمرار والانتشار وفشل العلاج» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q091","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Case","difficulty":"Hard","source":"PDF p. 191","question":{"en":"A chronic suspicious ulcer has negative microscopy for amastigotes, but clinical suspicion remains high. What is the best next test?","ar":"قرحة مزمنة مشتبهة كانت سلبية بالمجهر للأماستيغوت لكن الاشتباه السريري ما زال مرتفعًا. ما الفحص التالي الأفضل؟"},"options":[{"letter":"A","en":"Repeat only a urine dipstick","ar":"تكرار فحص البول فقط"},{"letter":"B","en":"Tzanck smear for HSV","ar":"مسحة تزانك للهربس"},{"letter":"C","en":"PCR on lesion material","ar":"PCR من مادة الآفة"},{"letter":"D","en":"No further testing","ar":"عدم إجراء فحوص أخرى"}],"correct":"C","explanation":{"en":"Parasite density may be low in chronic lesions, while PCR remains sensitive.","ar":"قد يكون الحمل الطفيلي منخفضًا في الآفات المزمنة بينما يظل PCR حساسًا."},"reasoning":{"en":"The decisive clue is negative microscopy despite high suspicion. This supports PCR on lesion material and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي سلبية المجهر رغم الاشتباه العالي؛ ولذلك تدعم الإجابة «PCR من مادة الآفة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q092","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Case","difficulty":"Hard","source":"PDF p. 191","question":{"en":"A patient with a cutaneous ulcer develops a chain of subcutaneous nodules extending proximally along lymphatics. What feature does this represent?","ar":"مريض لديه قرحة جلدية ظهرت لديه سلسلة عقيدات تحت الجلد تمتد لأعلى على مسار الأوعية اللمفية. ماذا تمثل هذه العلامة؟"},"options":[{"letter":"A","en":"Head-lice nits","ar":"صئبان قمل الرأس"},{"letter":"B","en":"Classic scabies burrows","ar":"أنفاق الجرب التقليدي"},{"letter":"C","en":"A normal scar","ar":"ندبة طبيعية"},{"letter":"D","en":"Nodular lymphangitis associated with cutaneous leishmaniasis","ar":"التهاب أوعية لمفية عقدي مرتبط بالليشمانيا الجلدية"}],"correct":"D","explanation":{"en":"Lymphatic spread can produce sporotrichoid nodules and is a marker of more extensive disease.","ar":"قد يسبب الانتشار اللمفي عقيدات على نمط السبوروتريكويد ويشير إلى مرض أوسع."},"reasoning":{"en":"The decisive clue is proximal nodules along lymphatics. This supports Nodular lymphangitis associated with cutaneous leishmaniasis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي عقيدات صاعدة على مسار اللمف؛ ولذلك تدعم الإجابة «التهاب أوعية لمفية عقدي مرتبط بالليشمانيا الجلدية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q093","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"Case","difficulty":"Hard","source":"PDF p. 192","question":{"en":"An immunocompetent patient has one 0.6-cm lesion on the forearm caused by a species without mucosal risk. There are no nodes or systemic features. Which approach is most reasonable?","ar":"مريض سليم المناعة لديه آفة واحدة 0.6 سم على الساعد بنوع لا يحمل خطرًا مخاطيًا، دون عقد أو أعراض جهازية. ما النهج الأكثر منطقية؟"},"options":[{"letter":"A","en":"Consider local therapy based on species and patient preference","ar":"التفكير في علاج موضعي حسب النوع وتفضيل المريض"},{"letter":"B","en":"Mandatory prolonged IV therapy for every lesion","ar":"علاج وريدي طويل إلزامي لكل آفة"},{"letter":"C","en":"Treat as crusted scabies","ar":"علاجها كجرب متقشر"},{"letter":"D","en":"Use pediculicide shampoo","ar":"استخدام شامبو للقمل"}],"correct":"A","explanation":{"en":"A single small low-risk lesion in an immunocompetent host meets uncomplicated criteria.","ar":"توافق الآفة الواحدة الصغيرة منخفضة الخطورة لدى سليم المناعة معايير المرض غير المعقد."},"reasoning":{"en":"The decisive clue is one small low-risk lesion with intact immunity. This supports Consider local therapy based on species and patient preference and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي آفة صغيرة واحدة منخفضة الخطورة مع سلامة المناعة؛ ولذلك تدعم الإجابة «التفكير في علاج موضعي حسب النوع وتفضيل المريض» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q094","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Case","difficulty":"Hard","source":"PDF p. 196","question":{"en":"A traveler walked barefoot on a tropical beach and five days later developed an intensely itchy winding raised track on the sole. What is the diagnosis?","ar":"مشى مسافر حافيًا على شاطئ استوائي وبعد خمسة أيام ظهر مسار مرتفع متعرج شديد الحكة على الأخمص. ما التشخيص؟"},"options":[{"letter":"A","en":"Scabies","ar":"الجرب"},{"letter":"B","en":"Cutaneous larva migrans","ar":"هجرة اليرقات الجلدية"},{"letter":"C","en":"Body lice","ar":"قمل الجسم"},{"letter":"D","en":"Localized leishmaniasis","ar":"الليشمانيا الموضعية"}],"correct":"B","explanation":{"en":"Barefoot exposure to contaminated sand followed by a creeping track is classic.","ar":"التعرض حافيًا لرمل ملوث ثم ظهور مسار زاحف صورة كلاسيكية."},"reasoning":{"en":"The decisive clue is beach exposure plus a migrating serpiginous track. This supports Cutaneous larva migrans and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التعرض للشاطئ مع مسار متعرج مهاجر؛ ولذلك تدعم الإجابة «هجرة اليرقات الجلدية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q095","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Case","difficulty":"Hard","source":"PDF p. 196","question":{"en":"A child sits in a sandbox frequented by stray cats and develops a serpiginous itchy lesion on the buttock. What is the likely source?","ar":"جلس طفل في صندوق رمل ترتاده قطط ضالة ثم ظهرت آفة متعرجة حاكة على الأرداف. ما المصدر المحتمل؟"},"options":[{"letter":"A","en":"Human head lice","ar":"قمل الرأس البشري"},{"letter":"B","en":"Female sandflies inside clothing seams","ar":"إناث ذباب الرمل في درزات الملابس"},{"letter":"C","en":"Animal hookworm larvae in contaminated soil","ar":"يرقات ديدان خطافية حيوانية في التربة الملوثة"},{"letter":"D","en":"Scabies mites from drinking water","ar":"عث الجرب من مياه الشرب"}],"correct":"C","explanation":{"en":"Cat and dog feces can contaminate sand with hookworm larvae that penetrate skin.","ar":"قد تلوث براز القطط والكلاب الرمل بيرقات الديدان الخطافية التي تخترق الجلد."},"reasoning":{"en":"The decisive clue is stray-animal contaminated sand. This supports Animal hookworm larvae in contaminated soil and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي رمل ملوث بحيوانات ضالة؛ ولذلك تدعم الإجابة «يرقات ديدان خطافية حيوانية في التربة الملوثة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q096","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Case","difficulty":"Hard","source":"PDF p. 197","question":{"en":"A patient with a classic creeping eruption has no fever and a normal blood count except mild eosinophilia. Is this compatible with uncomplicated CLM?","ar":"مريض لديه طفح زاحف كلاسيكي دون حمى وعد دم طبيعي عدا زيادة بسيطة بالحمضات. هل يتوافق ذلك مع هجرة يرقات غير معقدة؟"},"options":[{"letter":"A","en":"No; CLM always causes pancytopenia","ar":"لا؛ تسبب هجرة اليرقات دائمًا نقصًا شاملًا"},{"letter":"B","en":"No; it proves visceral leishmaniasis","ar":"لا؛ يثبت الليشمانيا الحشوية"},{"letter":"C","en":"No; it must be body lice","ar":"لا؛ لابد أن يكون قمل جسم"},{"letter":"D","en":"Yes; systemic symptoms are usually absent and eosinophilia may occasionally occur","ar":"نعم؛ تغيب الأعراض الجهازية غالبًا وقد تحدث زيادة الحمضات أحيانًا"}],"correct":"D","explanation":{"en":"CLM is normally confined to the skin, with only occasional laboratory eosinophilia.","ar":"تبقى هجرة اليرقات عادةً محصورة بالجلد مع زيادة حمضات مخبرية أحيانًا."},"reasoning":{"en":"The decisive clue is localized disease with absent systemic illness. This supports Yes; systemic symptoms are usually absent and eosinophilia may occasionally occur and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي مرض موضعي دون اعتلال جهازي؛ ولذلك تدعم الإجابة «نعم؛ تغيب الأعراض الجهازية غالبًا وقد تحدث زيادة الحمضات أحيانًا» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q097","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Case","difficulty":"Hard","source":"PDF p. 198","question":{"en":"A CLM track becomes increasingly painful, warm, and purulent after scratching. What complication has developed?","ar":"أصبح مسار هجرة اليرقات مؤلمًا ودافئًا ومفرزًا للصديد بعد الحك. ما المضاعفة؟"},"options":[{"letter":"A","en":"Secondary bacterial infection","ar":"عدوى بكتيرية ثانوية"},{"letter":"B","en":"Normal larval migration","ar":"هجرة طبيعية لليرقة"},{"letter":"C","en":"Leishmaniasis recidivans","ar":"ليشمانيا ناكسة"},{"letter":"D","en":"Post-scabetic nodules","ar":"عقيدات ما بعد الجرب"}],"correct":"A","explanation":{"en":"Broken skin from scratching can permit bacterial superinfection.","ar":"يسمح تمزق الجلد الناتج عن الحك بعدوى بكتيرية ثانوية."},"reasoning":{"en":"The decisive clue is new warmth, pain, and pus. This supports Secondary bacterial infection and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي ظهور الدفء والألم والصديد؛ ولذلك تدعم الإجابة «عدوى بكتيرية ثانوية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q098","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Case","difficulty":"Hard","source":"PDF p. 198","question":{"en":"A pregnant woman has one localized CLM track and severe itch. Which therapy is most suitable when systemic drugs are being avoided?","ar":"حامل لديها مسار واحد موضعي من هجرة اليرقات مع حكة شديدة. ما العلاج الأنسب عند تجنب الأدوية الجهازية؟"},"options":[{"letter":"A","en":"Oral ivermectin","ar":"إيفرمكتين فموي"},{"letter":"B","en":"Topical thiabendazole","ar":"ثيابندازول موضعي"},{"letter":"C","en":"High-dose lindane","ar":"ليندان بجرعة عالية"},{"letter":"D","en":"No symptomatic care is allowed","ar":"لا يسمح بأي علاج عرضي"}],"correct":"B","explanation":{"en":"Topical thiabendazole is useful for localized disease and avoids systemic exposure.","ar":"يفيد الثيابندازول الموضعي في المرض المحدود ويجنب التعرض الجهازي."},"reasoning":{"en":"The decisive clue is pregnancy with one localized track. This supports Topical thiabendazole and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الحمل مع مسار موضعي واحد؛ ولذلك تدعم الإجابة «ثيابندازول موضعي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q099","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Case","difficulty":"Hard","source":"PDF p. 198","question":{"en":"A 12-kg child has extensive CLM. Which commonly used oral drug should be avoided because of weight?","ar":"طفل وزنه 12 كجم لديه هجرة يرقات واسعة. أي دواء فموي شائع يجب تجنبه بسبب الوزن؟"},"options":[{"letter":"A","en":"Albendazole under an appropriate pediatric plan","ar":"ألبيندازول ضمن خطة أطفال مناسبة"},{"letter":"B","en":"An antihistamine","ar":"مضاد هيستامين"},{"letter":"C","en":"Ivermectin","ar":"إيفرمكتين"},{"letter":"D","en":"Topical anti-inflammatory care","ar":"علاج موضعي مضاد للالتهاب"}],"correct":"C","explanation":{"en":"Ivermectin is generally avoided below 15 kg because safety data are insufficient.","ar":"يُتجنب الإيفرمكتين عادةً تحت 15 كجم لعدم كفاية بيانات الأمان."},"reasoning":{"en":"The decisive clue is weight below 15 kg. This supports Ivermectin and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي وزن أقل من 15 كجم؛ ولذلك تدعم الإجابة «إيفرمكتين» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q100","topic":"cutaneous-larva-migrans","topicEn":"Cutaneous Larva Migrans","topicAr":"هجرة اليرقات الجلدية","type":"Case","difficulty":"Hard","source":"PDF p. 197","question":{"en":"A patient marks the tip of a serpiginous lesion each morning; it advances nearly 2 cm daily. What does this observation support?","ar":"يحدد مريض طرف آفة متعرجة كل صباح فتتقدم نحو 2 سم يوميًا. ماذا يدعم ذلك؟"},"options":[{"letter":"A","en":"A static allergic contact dermatitis","ar":"التهاب جلد تماسي ثابت"},{"letter":"B","en":"A healed leishmaniasis scar","ar":"ندبة ليشمانيا ملتئمة"},{"letter":"C","en":"Inactive nits","ar":"صئبان غير نشطة"},{"letter":"D","en":"Active cutaneous larva migrans","ar":"هجرة يرقات جلدية نشطة"}],"correct":"D","explanation":{"en":"Visible daily advancement is characteristic of a migrating hookworm larva.","ar":"يُعد التقدم اليومي المرئي مميزًا ليرقة دودة خطافية مهاجرة."},"reasoning":{"en":"The decisive clue is 1–2 cm daily progression. This supports Active cutaneous larva migrans and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي تقدم 1–2 سم يوميًا؛ ولذلك تدعم الإجابة «هجرة يرقات جلدية نشطة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null}]);
